from collections import OrderedDict, defaultdict


class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.store = OrderedDict()  # key -> value, ordered oldest..newest

    def get(self, key: int) -> int:
        if key not in self.store:
            return -1
        self.store.move_to_end(key)  # touch -> most recent
        return self.store[key]

    def put(self, key: int, value: int) -> None:
        if key in self.store:
            self.store[key] = value
            self.store.move_to_end(key)
            return
        if len(self.store) >= self.capacity:
            self.store.popitem(last=False)  # evict oldest (head)
        self.store[key] = value


class LFUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.key_to_val = {}
        self.key_to_freq = {}
        self.buckets = defaultdict(OrderedDict)  # freq -> OrderedDict of keys
        self.min_freq = 0

    def _bump(self, key: int) -> None:
        f = self.key_to_freq[key]
        del self.buckets[f][key]
        if not self.buckets[f]:
            del self.buckets[f]
            if self.min_freq == f:
                self.min_freq += 1
        self.key_to_freq[key] = f + 1
        self.buckets[f + 1][key] = None

    def get(self, key: int) -> int:
        if key not in self.key_to_val:
            return -1
        self._bump(key)
        return self.key_to_val[key]

    def put(self, key: int, value: int) -> None:
        if self.capacity <= 0:
            return
        if key in self.key_to_val:
            self.key_to_val[key] = value
            self._bump(key)
            return
        if len(self.key_to_val) >= self.capacity:
            old_key, _ = self.buckets[self.min_freq].popitem(last=False)
            if not self.buckets[self.min_freq]:
                del self.buckets[self.min_freq]
            del self.key_to_val[old_key]
            del self.key_to_freq[old_key]
        self.key_to_val[key] = value
        self.key_to_freq[key] = 1
        self.buckets[1][key] = None
        self.min_freq = 1


def run(commands, capacity, policy):
    cache = LRUCache(capacity) if policy == "LRU" else LFUCache(capacity)
    out = []
    for cmd in commands:
        if cmd[0] == "GET":
            out.append(cache.get(cmd[1]))
        else:
            cache.put(cmd[1], cmd[2])
    return out


# Sample 1 (LRU)
print("LRU sample:", run([("PUT",1,10),("PUT",2,20),("GET",1),("PUT",3,30),("GET",2),("GET",3)], 2, "LRU"))
# expected 10, -1, 30

