# expected 5, 5, -1, 7

# LFU tie-break: both reach freq 2, evict LRU among them (key 1)
print("LFU tie:", run([("PUT",1,1),("PUT",2,2),("GET",1),("GET",2),("PUT",3,3),("GET",1),("GET",2),("GET",3)], 2, "LFU"))
# 1 then 2 from gets; PUT 3 evicts key1; GET1->-1, GET2->2, GET3->3  => [1,2,-1,2,3]

# Edge: capacity 1
