class Node:
    __slots__ = ("key", "val", "prev", "next")

    def __init__(self, key=0, val=0):
        self.key = key
        self.val = val
        self.prev = None
        self.next = None


class DoublyLinkedList:
    """Sentinel head/tail. head.next = oldest (LRU), tail.prev = newest (MRU)."""

    def __init__(self):
        self.head = Node()
        self.tail = Node()
        self.head.next = self.tail
        self.tail.prev = self.head

    def add_to_back(self, node):  # newest end
        prev = self.tail.prev
        prev.next = node
        node.prev = prev
        node.next = self.tail
        self.tail.prev = node

    def remove(self, node):
        node.prev.next = node.next
        node.next.prev = node.prev

    def pop_front(self):  # remove + return oldest real node
        if self.head.next is self.tail:
            return None
        node = self.head.next
        self.remove(node)
        return node

    def is_empty(self):
        return self.head.next is self.tail


class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.map = {}              # key -> Node
        self.dll = DoublyLinkedList()

    def get(self, key: int) -> int:
        if key not in self.map:
            return -1
        node = self.map[key]
        self.dll.remove(node)
        self.dll.add_to_back(node)   # touch -> most recent
        return node.val

    def put(self, key: int, value: int) -> None:
        if key in self.map:
            node = self.map[key]
            node.val = value
            self.dll.remove(node)
            self.dll.add_to_back(node)
            return
        if len(self.map) >= self.capacity:
            oldest = self.dll.pop_front()     # evict LRU
            del self.map[oldest.key]
        node = Node(key, value)
        self.map[key] = node
        self.dll.add_to_back(node)


class LFUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.map = {}                 # key -> Node
        self.freq = {}                # key -> frequency
        self.buckets = {}             # freq -> DoublyLinkedList of nodes (oldest..newest)
        self.min_freq = 0

    def _bump(self, node):
        f = self.freq[node.key]
        self.buckets[f].remove(node)
        if self.buckets[f].is_empty():
            del self.buckets[f]
            if self.min_freq == f:
                self.min_freq += 1
        self.freq[node.key] = f + 1
        if f + 1 not in self.buckets:
            self.buckets[f + 1] = DoublyLinkedList()
        self.buckets[f + 1].add_to_back(node)

    def get(self, key: int) -> int:
        if key not in self.map:
            return -1
        node = self.map[key]
        self._bump(node)
        return node.val

    def put(self, key: int, value: int) -> None:
        if self.capacity <= 0:
            return
        if key in self.map:
            node = self.map[key]
            node.val = value
            self._bump(node)
            return
        if len(self.map) >= self.capacity:
            victim = self.buckets[self.min_freq].pop_front()  # LRU in lowest-freq bucket
            if self.buckets[self.min_freq].is_empty():
                del self.buckets[self.min_freq]
            del self.map[victim.key]
            del self.freq[victim.key]
        node = Node(key, value)
        self.map[key] = node
        self.freq[key] = 1
        if 1 not in self.buckets:
            self.buckets[1] = DoublyLinkedList()
        self.buckets[1].add_to_back(node)
        self.min_freq = 1


def run(commands, capacity, policy):
    cache = LRUCache(capacity) if policy == "LRU" else LFUCache(capacity)
    out = []
    for cmd in commands:
        if cmd[0] == "GET":
            out.append(cache.get(cmd[1]))
        else:
            cache.put(cmd[1], cmd[2])
    return out


