# cross-check DLL versions against OrderedDict versions on random inputs
import random
from collections import OrderedDict, defaultdict

class LRURef:
    def __init__(self, c): self.c=c; self.s=OrderedDict()
    def get(self,k):
        if k not in self.s: return -1
        self.s.move_to_end(k); return self.s[k]
    def put(self,k,v):
        if k in self.s: self.s[k]=v; self.s.move_to_end(k); return
        if len(self.s)>=self.c: self.s.popitem(last=False)
        self.s[k]=v

class LFURef:
    def __init__(self,c): self.c=c; self.kv={}; self.kf={}; self.b=defaultdict(OrderedDict); self.mf=0
    def _b(self,k):
        f=self.kf[k]; del self.b[f][k]
        if not self.b[f]:
            del self.b[f]
            if self.mf==f: self.mf+=1
        self.kf[k]=f+1; self.b[f+1][k]=None
    def get(self,k):
        if k not in self.kv: return -1
        self._b(k); return self.kv[k]
    def put(self,k,v):
        if self.c<=0: return
        if k in self.kv: self.kv[k]=v; self._b(k); return
        if len(self.kv)>=self.c:
            ok,_=self.b[self.mf].popitem(last=False)
            if not self.b[self.mf]: del self.b[self.mf]
            del self.kv[ok]; del self.kf[ok]
        self.kv[k]=v; self.kf[k]=1; self.b[1][k]=None; self.mf=1

ok = True
